import datetime

from seed import BillPayOutDataRequest, SeedApi
from seed.money_out_types import (
    AuthorizePaymentMethod,
    RequestOutAuthorizeVendorData,
)
from seed.payout_subscription import PayoutPaymentDetail, PayoutScheduleDetail

client = SeedApi(
    api_key="YOUR_API_KEY",
)
client.payout_subscription.create_payout_subscription(
    entry_point="d193cf9a46",
    payment_method=AuthorizePaymentMethod(
        method="vcard",
    ),
    payment_details=PayoutPaymentDetail(
        total_amount=250.0,
        service_fee=0.0,
    ),
    vendor_data=RequestOutAuthorizeVendorData(
        vendor_id=1501,
    ),
    bill_data=[
        BillPayOutDataRequest(
            invoice_number="INV-7820",
            net_amount="250",
            invoice_date=datetime.date.fromisoformat(
                "2025-08-15",
            ),
            due_date=datetime.date.fromisoformat(
                "2025-09-01",
            ),
        )
    ],
    schedule_details=PayoutScheduleDetail(
        start_date="09/01/2025",
        frequency="weekly",
        end_date="untilcancelled",
    ),
)
